mapper.update:
UPDATE mcp_session
SET last_active_at = #{lastActiveAt},
    expire_at = #{expireAt},
    last_method = #{lastMethod}
WHERE id = #{id}

mapper.select:
SELECT id, session_id, user_id, token_id, protocol_version, client_info,
       state, last_method, create_time, last_active_at, expire_at, close_time
FROM mcp_session
WHERE expire_at < #{now}
ORDER BY expire_at ASC
LIMIT #{limit}

mapper.update:
UPDATE mcp_session
SET state = 'CLOSED',
    close_time = #{closeTime}
WHERE id = #{id}
